import{_ as s,c as e,o as a,a as l}from"./app.7aa4ec1b.js";const y=JSON.parse('{"title":"子模块","description":"","frontmatter":{},"headers":[{"level":2,"title":".gitmodules","slug":"gitmodules","link":"#gitmodules","children":[]},{"level":2,"title":"submodule","slug":"submodule","link":"#submodule","children":[]}],"relativePath":"1.基础/3.git/子模块.md","lastUpdated":1697094879000}'),o={name:"1.基础/3.git/子模块.md"},n=l(`<h1 id="子模块" tabindex="-1">子模块 <a class="header-anchor" href="#子模块" aria-hidden="true">#</a></h1><p>Git 子模块是一种允许您在一个 Git 仓库中嵌套其他 Git 仓库的机制。这允许您在一个仓库中包含其他项目作为子模块，以便在父项目中引用、管理和使用这些子项目的特定版本。以下是如何使用 Git 子模块的基本步骤：</p><p><strong>添加子模块</strong>：首先，您需要将子模块添加到您的主项目中。假设您已经有一个主项目，可以使用以下命令添加子模块：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki one-dark-pro vp-code-dark" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">git </span><span style="color:#98C379;">submodule</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">add</span><span style="color:#ABB2BF;"> &lt;</span><span style="color:#98C379;">URL_to_submodule_repositor</span><span style="color:#ABB2BF;">y&gt; </span><span style="color:#98C379;">path/to/submodule</span></span>
<span class="line"></span></code></pre><pre class="shiki min-dark vp-code-light" tabindex="0"><code><span class="line"><span style="color:#B392F0;">git </span><span style="color:#9DB1C5;">submodule</span><span style="color:#B392F0;"> </span><span style="color:#9DB1C5;">add</span><span style="color:#B392F0;"> </span><span style="color:#F97583;">&lt;</span><span style="color:#9DB1C5;">URL_to_submodule_repositor</span><span style="color:#B392F0;">y</span><span style="color:#F97583;">&gt;</span><span style="color:#B392F0;"> </span><span style="color:#9DB1C5;">path/to/submodule</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><code>&lt;URL_to_submodule_repository&gt;</code> 是子模块的远程仓库 URL。</li><li><code>path/to/submodule</code> 是子模块将存储在主项目中的路径。</li></ul><h2 id="gitmodules" tabindex="-1">.gitmodules <a class="header-anchor" href="#gitmodules" aria-hidden="true">#</a></h2><p>.gitmodules 是 Git 用来管理子模块的文件，子模块是一个 Git 仓库中包含另一个 Git 仓库。</p><p>该文件存储在 Git 仓库的根目录下，用于记录当前仓库中使用的子模块信息，包括子模块的名称、URL、分支等信息。</p><p>在执行 <code>git clone</code> 命令时，子模块不会自动初始化和更新，需要手动执行 <code>git submodule init</code> 和 <code>git submodule update</code> 命令来完成子模块的初始化和更新。</p><p>如果要添加或删除子模块，需要修改 .gitmodules 文件并执行相应的命令来更新子模块。</p><h2 id="submodule" tabindex="-1">submodule <a class="header-anchor" href="#submodule" aria-hidden="true">#</a></h2><p>修改完 .gitmodules 文件后，需要使用以下命令更新 Git 仓库的子模块：</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki one-dark-pro vp-code-dark" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">git </span><span style="color:#98C379;">submodule</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">update</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--init</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">--recursive</span></span>
<span class="line"></span></code></pre><pre class="shiki min-dark vp-code-light" tabindex="0"><code><span class="line"><span style="color:#B392F0;">git </span><span style="color:#9DB1C5;">submodule</span><span style="color:#B392F0;"> </span><span style="color:#9DB1C5;">update</span><span style="color:#B392F0;"> </span><span style="color:#9DB1C5;">--init</span><span style="color:#B392F0;"> </span><span style="color:#9DB1C5;">--recursive</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>该命令会按照新的 .gitmodules 文件重新初始化子模块，并更新子模块所在的仓库</p>`,14),p=[n];function t(i,r,d,c,u,m){return a(),e("div",null,p)}const h=s(o,[["render",t]]);export{y as __pageData,h as default};
